const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
const imageKey = binaryKeys.includes('image') ? 'image' : binaryKeys[0];
const image = imageKey ? item.binary[imageKey] : null;
if (!image?.data) {
  throw new Error('未收到圖片檔案。HTML FormData 欄位請命名為 image。');
}

const body = item.json || {};
const operatorRaw = body.operator || body.operatorJson || '{}';
let operator = {};
try {
  operator = typeof operatorRaw === 'string' ? JSON.parse(operatorRaw) : operatorRaw;
} catch (error) {
  operator = {};
}

const prompt = `你是製造業「現場補料單」OCR 與資料結構化助手。請辨識圖片中的單據資料，嚴格以 JSON 格式輸出，不要輸出 markdown 標記（如 \`\`\`json），也不要加上任何解釋文字。

【一、資料擷取核心邏輯】
1. 全局預判：請先掃描圖片中的表格，確認共有幾列明細，並將數字填入 total_detected_rows。
2. 換列判定：只要有獨立的「品號」、「規格」或「數量」出現，即視為獨立的一筆明細，必須與上下列分開。
3. 絕對完整性：看見幾列就必須輸出幾個 items。若某列字跡模糊或資料缺失，仍須保留該列，將無法辨識的欄位填入空字串或 0，並於 note 註明「字跡模糊無法判讀」。不可擅自忽略或整併正常資料。
4. 空白列排除：表格下方只有 #N/A 或完全空白且沒有品號、規格、數量的列，不算明細，不要輸出。

【二、欄位業務規則】
1. 共通資訊：表頭的「日期」請統一套用至所有 items。若每列製令單號相同，order_no 填主要製令單號；每列仍需在 work_order_no 填入該列製令單號。
2. 日期：若圖片為民國年，例如 115/2/13，請轉成西元 2026-02-13T00:00:00+08:00。無法判讀則輸出空字串。
3. 品號 part_no：
   - 第一個字元必須是英文大寫 A-Z。
   - 優先進行 OCR 誤讀校正：首碼若為 0 修正為 O；1 修正為 I；5 修正為 S；8 修正為 B。
   - 若校正後仍無法確認首碼為英文，請輸出空字串，並在 note 寫明「品號開頭非英文或無法確認」。
4. 規格 spec：包含尺寸、材質、百分比、中文描述或特殊符號，請完整保留原始文字，勿翻譯、勿截斷、勿合併相鄰列。
5. 數量欄位：只輸出數字；無法判讀時輸出 0。手寫數字若位於「實領數量」欄，請判斷為 received_qty；不要把勾勾、分數註記或括號當作規格。
6. 備註欄：請保留該列備註；沒有問題則填 OK。

【三、輸出 JSON 結構】
請嚴格遵守以下格式，確保可被 JSON.parse() 解析：
{
  "total_detected_rows": 0,
  "order_no": "製令單號或單據號碼，無法判讀則空字串",
  "date": "YYYY-MM-DDTHH:mm:ss+08:00，無法判讀則空字串",
  "items": [
    {
      "row_no": 1,
      "work_order_no": "該列製令單號；若只有表頭製令單號，請填表頭值；無法判讀則空字串",
      "part_no": "首碼必為英文，無法確認則空字串",
      "spec": "完整規格描述，無法判讀則空字串",
      "defective_qty": 0,
      "request_qty": 0,
      "received_qty": 0,
      "note": "備註、異常原因；沒有問題則填 OK"
    }
  ]
}`;

return [{
  json: {
    startedAt: new Date().toISOString(),
    imageId: `${image.fileName || ''}|${image.fileSize || ''}`,
    operator,
    imageMeta: {
      fileName: image.fileName || '',
      mimeType: image.mimeType || 'image/jpeg',
      fileSize: image.fileSize || ''
    },
    prompt
  },
  binary: { image }
}];

function getGeminiText(payload) {
  for (const key of ['text', 'output', 'content', 'response', 'result', 'completion']) {
    if (typeof payload[key] === 'string' && payload[key].trim()) return payload[key].trim();
  }
  if (typeof payload.message?.content === 'string') return payload.message.content.trim();
  if (Array.isArray(payload.content?.parts)) {
    const text = payload.content.parts.find((part) => typeof part.text === 'string')?.text;
    if (text) return text.trim();
  }
  const text = payload.candidates?.[0]?.content?.parts?.find((part) => typeof part.text === 'string')?.text || '';
  return text.trim();
}

function parseJsonText(rawText) {
  if (!rawText) throw new Error('Gemini 未回傳文字內容');
  try {
    return JSON.parse(rawText);
  } catch (error) {
    const cleaned = rawText.replace(/^```json/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
    try {
      return JSON.parse(cleaned);
    } catch (innerError) {
      const match = rawText.match(/\{[\s\S]*\}/);
      if (!match) throw new Error('Gemini 回傳非 JSON');
      return JSON.parse(match[0]);
    }
  }
}

const requestMeta = $('準備 Gemini 請求').first().json;
const ocr = parseJsonText(getGeminiText($json));
const items = Array.isArray(ocr.items) ? ocr.items : [];
if (!items.length) throw new Error('OCR 結果沒有 items 明細');

return [{
  json: {
    ocr,
    operator: requestMeta.operator || {},
    imageMeta: requestMeta.imageMeta || {},
    startedAt: requestMeta.startedAt || '',
    imageId: requestMeta.imageId || ''
  }
}];

const ocrPayload = $('解析 OCR JSON').first().json;
const ocr = ocrPayload.ocr || {};
const operator = ocrPayload.operator || {};
const imageMeta = ocrPayload.imageMeta || {};
const masterItems = $input.all().map((item) => item.json);
const startedAt = ocrPayload.startedAt || new Date().toISOString();
const imageId = ocrPayload.imageId || '';
const batchId = `OCR-${startedAt.replace(/[-:.TZ]/g, '').slice(0, 14)}`;

function num(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function normalize(value) {
  return String(value || '')
    .toUpperCase()
    .replace(/\s+/g, '')
    .replace(/[，,。.;；:：()（）\[\]【】"'「」]/g, '')
    .trim();
}

function getValue(obj, keys) {
  for (const key of keys) {
    if (obj?.[key] !== undefined && obj?.[key] !== null) return obj[key];
  }
  return '';
}

function isValidPartNo(value) {
  return /^[A-Za-z]/.test(String(value || '').trim());
}

function propVal(row, name) {
  const p = row?.properties?.[name];
  if (p) {
    switch (p.type) {
      case 'title': return (p.title || []).map((t) => t.plain_text).join('');
      case 'rich_text': return (p.rich_text || []).map((t) => t.plain_text).join('');
      case 'select': return p.select?.name || '';
      case 'number': return p.number ?? '';
      default: return '';
    }
  }
  for (const k of [name, 'property_' + name]) {
    if (row?.[k] !== undefined && row?.[k] !== null) return row[k];
  }
  return '';
}

const masterMap = new Map();
for (const master of masterItems) {
  const partNo = String(propVal(master, '品號') || master.name || '').trim();
  const spec = String(propVal(master, '規格')).trim();
  if (partNo) masterMap.set(normalize(partNo), { partNo, spec });
}

let items = Array.isArray(ocr.items) ? ocr.items : [];
items = items.filter((item) => {
  const partNo = String(item.part_no || '').trim();
  const spec = String(item.spec || '').trim();
  return partNo || spec || item.note;
});

const rows = items.map((item, index) => {
  const partNo = String(item.part_no || '').trim();
  const spec = String(item.spec || '').trim();
  const workOrderNo = String(item.work_order_no || ocr.order_no || '').trim();
  const master = masterMap.get(normalize(partNo));
  const masterSpec = master?.spec || '';
  const orderNoCheck = Boolean(workOrderNo && workOrderNo !== '未判讀');
  const partNoStartsOk = isValidPartNo(partNo);
  const partNoCheck = Boolean(partNoStartsOk && master);
  const specCheck = Boolean(master && normalize(masterSpec) && normalize(spec) && normalize(masterSpec) === normalize(spec));
  const notes = [];
  const errorTypes = [];
  if (!orderNoCheck) { notes.push('製令單號未判讀'); errorTypes.push('製令單號未判讀'); }
  if (!partNo) { notes.push('品號未判讀'); errorTypes.push('品號未判讀'); }
  if (partNo && !partNoStartsOk) { notes.push('品號開頭非英文'); errorTypes.push('品號開頭非英文'); }
  if (partNoStartsOk && !master) { notes.push('主檔查無品號'); errorTypes.push('主檔查無品號'); }
  if (!spec) { notes.push('規格未判讀'); errorTypes.push('規格未判讀'); }
  if (master && !specCheck) { notes.push(`規格不符；主檔：${masterSpec || '空值'}`); errorTypes.push('規格不符'); }
  if (item.note && String(item.note).trim() !== 'OK') {
    notes.push(String(item.note));
    if (/模糊|無法判讀|不清|看不清/.test(String(item.note))) errorTypes.push('字跡模糊');
  }
  const status = orderNoCheck && partNoCheck && specCheck ? 'OK' : '異常';
  const ocrStatus = partNo && spec ? '辨識完成' : '辨識不完整';

  return {
    rowNo: num(item.row_no) || index + 1,
    status,
    ocrStatus,
    orderNo: ocr.order_no || '',
    workOrderNo,
    date: ocr.date || '',
    partNo,
    spec,
    masterSpec,
    defectiveQty: num(item.defective_qty),
    requestQty: num(item.request_qty),
    receivedQty: num(item.received_qty),
    orderNoCheck,
    partNoCheck,
    specCheck,
    errorTypes,
    note: notes.join('；') || 'OK'
  };
});

const total = rows.length;
const abnormal = rows.filter((row) => row.status !== 'OK').length;

const completedAt = new Date().toISOString();
const processingSeconds = Math.max(0, Math.round((new Date(completedAt).getTime() - new Date(startedAt).getTime()) / 100) / 10);

return [{
  json: {
    batchId,
    imageId,
    startedAt,
    completedAt,
    processingSeconds,
    notifyStatus: '前端回傳',
    operator,
    imageMeta,
    order_no: ocr.order_no || rows[0]?.workOrderNo || '',
    date: ocr.date || '',
    total,
    passed: total - abnormal,
    abnormal,
    rows
  }
}];

const compare = $('比對 OCR 與品項主檔').first().json;
const batchPage = $input.first().json;

return compare.rows.map((row) => ({
  json: {
    ...row,
    batchId: compare.batchId,
    batchUrl: batchPage.url || '',
    operator: compare.operator || {},
    summary: {
      order_no: compare.order_no,
      date: compare.date,
      total: compare.total,
      passed: compare.passed,
      abnormal: compare.abnormal
    }
  }
}));

const compare = $('比對 OCR 與品項主檔').first().json;
const details = $('準備明細寫入資料').all().map((item) => item.json);
const createdPages = $input.all().map((item) => item.json);

return [{
  json: {
    ok: true,
    batchId: compare.batchId,
    order_no: compare.order_no,
    date: compare.date,
    total: compare.total,
    passed: compare.passed,
    abnormal: compare.abnormal,
    results: details.map((row, index) => ({
      status: row.status,
      partNo: row.partNo,
      spec: row.spec,
      defectiveQty: row.defectiveQty,
      requestQty: row.requestQty,
      receivedQty: row.receivedQty,
      note: row.note,
      notionUrl: createdPages[index]?.url || ''
    }))
  }
}];

const wh = $('HTML OCR Webhook').first();
const body = wh.json?.body || wh.json || {};
let operator = {};
try {
  operator = typeof body.operator === 'string' ? JSON.parse(body.operator) : (body.operator || {});
} catch (e) {
  operator = {};
}
const userId = String(operator.userId || operator.user_id || body.userId || '').trim();
const people = $input.all().map((i) => i.json || {});

function propVal(row, name) {
  const p = row?.properties?.[name];
  if (p) {
    switch (p.type) {
      case 'title': return (p.title || []).map((t) => t.plain_text).join('');
      case 'rich_text': return (p.rich_text || []).map((t) => t.plain_text).join('');
      case 'select': return p.select?.name || '';
      case 'multi_select': return (p.multi_select || []).map((o) => o.name);
      default: return '';
    }
  }
  for (const k of [name, 'property_' + name]) {
    if (row?.[k] !== undefined && row?.[k] !== null) return row[k];
  }
  return '';
}
function toList(value) {
  if (Array.isArray(value)) return value.map((x) => String(x?.name || x).trim()).filter(Boolean);
  const t = String(value ?? '').trim();
  if (!t) return [];
  try { const p = JSON.parse(t); if (Array.isArray(p)) return p.map((x) => String(x?.name || x).trim()).filter(Boolean); } catch (e) {}
  return t.split(/[,，、]/).map((s) => s.trim()).filter(Boolean);
}

const matched = people.find((p) => String(propVal(p, 'LINE userId')).trim() === userId && userId);
const status = matched ? String(propVal(matched, '狀態')).trim() : '';
const features = matched ? toList(propVal(matched, '可使用功能')) : [];
const allowed = Boolean(matched && status === '已開通' && features.includes('OCR補料單'));
const operatorName = String(operator.name || operator.displayName || (matched ? propVal(matched, '名稱') : '') || '').trim();

return [{
  json: {
    ...wh.json,
    _allowed: allowed,
    _userId: userId,
    _operatorName: operatorName,
    _status: matched ? (status || '待審核') : '未建立',
    _nowIso: new Date().toISOString()
  },
  binary: wh.binary
}];
